31	  describe(`${params.pluginId} package manifest contract`, () => {
32	    if (params.runtimeDeps?.length) {
33	      for (const dependencyName of params.runtimeDeps) {
34	        it(`keeps ${dependencyName} plugin-local`, () => {
35	          const rootManifest = readJson<PackageManifest>("package.json");
36	          const pluginManifest = readJson<PackageManifest>(packagePath);
37	          const pluginSpec = pluginManifest.dependencies?.[dependencyName];
38	          const rootSpec = rootManifest.dependencies?.[dependencyName];
39	
40	          expect(pluginSpec).toBeTruthy();
41	          expect(rootSpec).toBeUndefined();
42	        });
43	      }
44	    }
45	
46	    const minHostVersionBaseline = params.minHostVersionBaseline;
47	    if (minHostVersionBaseline) {
48	      it("declares a parseable minHostVersion floor at or above the baseline", () => {
49	        const baseline = parseSemver(minHostVersionBaseline);
50	        expect(baseline).not.toBeNull();
51	        if (!baseline) {
52	          return;
53	        }
54	
55	        const manifest = readJson<PackageManifest>(packagePath);
56	        const requirement = parseMinHostVersionRequirement(
57	          manifest.openclaw?.install?.minHostVersion ?? null,
58	        );
59	
60	        expect(
61	          requirement,
62	          `${packagePath} should declare openclaw.install.minHostVersion`,
63	        ).not.toBeNull();
64	        if (!requirement) {
65	          return;
66	        }
67	
68	        const minimum = parseSemver(requirement.minimumLabel);
