70	        if (!minimum) {
71	          return;
72	        }
73	
74	        expect(
75	          isAtLeast(minimum, baseline),
76	          `${packagePath} should require at least OpenClaw ${minHostVersionBaseline}`,
77	        ).toBe(true);
