export function normalizeIrcMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();

  // Strip prefixes
  let target = trimmed;
  if (lowered.startsWith("irc:")) target = target.slice("irc:".length);
  if (lowered.startsWith("channel:")) target = `#${target}`;
  if (lowered.startsWith("user:")) target = target.slice("user:".length);

  // Validate
  if (!looksLikeIrcTargetId(target)) return undefined;
  return target;
}

export function isChannelTarget(target: string): boolean {
  return target.startsWith("#") || target.startsWith("&");
}
