### Step 9: `extensions/pulseboard/src/send.ts`

Outbound message sending. Mirrors Nostr's inline send but extracts it to a dedicated file
like IRC's `send.ts`. Accesses the active client handle stored during gateway startup.

```typescript
// Module-level map of active client handles per accountId
const activeClients = new Map<string, PulseBoardClientHandle>();

export function setPulseBoardClient(accountId: string, client: PulseBoardClientHandle): void { ... }
export function clearPulseBoardClient(accountId: string): void { ... }

export async function sendMessagePulseBoard(params: {
  to: string;         // "board:<name>" or "<userId>"
  text: string;
  accountId?: string | null;
}): Promise<{ to: string; messageId: string }> {
  const aid = normalizeAccountId(params.accountId ?? DEFAULT_ACCOUNT_ID);
  const client = activeClients.get(aid);
  if (!client?.isConnected()) {
    throw new Error(`PulseBoard client not running for account ${aid}`);
  }
  if (params.to.startsWith("board:")) {
    const boardName = params.to.slice("board:".length);
    await client.postToBoard(boardName, params.text);
  } else {
    await client.sendDm(params.to, params.text);
  }
  return { to: params.to, messageId: `pb-${Date.now()}` };
}
```

