### Step 13: `extensions/pulseboard/src/channel.ts`

Main plugin definition. Uses `createChatChannelPlugin`.

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin boards and direct messages via PulseBoard",
      order: 90,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,          // createTopLevelChannelConfigAdapter
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl, username: account.username },
        }),
    },
    messaging: {
      normalizeTarget: (target) => {
        // Accept "board:<name>" for boards, plain username for DMs
        const trimmed = target.trim().replace(/^pulseboard:/i, "");
        return trimmed || undefined;
      },
      targetResolver: {
        looksLikeId: (input) => {
          const t = input.trim();
          return t.startsWith("board:") || /^[a-zA-Z0-9_.-]+$/.test(t);
        },
        hint: "<username|board:<name>>",
      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      collectStatusIssues: (accounts) =>
        collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          serverUrl: snapshot.serverUrl ?? null,
          username: snapshot.username ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          serverUrl: account.serverUrl,
          username: account.username,
          ...buildTrafficStatusSummary(runtime),
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" (need token in channels.pulseboard).`,
          );
        }
        ctx.log?.info(`[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`);
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardProvider({
              accountId: account.accountId,
              cfg: ctx.cfg as CoreConfig,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => entry.trim().toLowerCase(),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard({ to: id, text: message });
      },
    },
  },
  security: {
    resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
      channelKey: "pulseboard",
      resolvePolicy: (account) => account.config.dmPolicy,
      resolveAllowFrom: (account) => account.config.allowFrom,
      policyPathSuffix: "dmPolicy",
      defaultPolicy: "pairing",
      // approveHint omitted — createScopedDmSecurityResolver generates default hint from channelKey
      normalizeEntry: (raw) => raw.trim().toLowerCase(),
    }),
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseBoardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg, channel: "pulseboard", accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
      const result = await sendMessagePulseBoard({ to, text: message, accountId: aid });
      return attachChannelToResult("pulseboard", result);
    },
  },
});
