### Step 10: `extensions/pulseboard/src/inbound.ts`

Inbound message handler. Handles both DM and board messages.

**DM path** — follows Nostr's `onMessage` handler:
- Resolve DM access with `resolveInboundDirectDmAccessWithRuntime` (requires `isSenderAllowed`)
- Dispatch with `dispatchInboundDirectDmWithRuntime` where `peer: { kind: "direct", id: senderId }`

**Board path** — follows IRC's group pattern but uses the same `dispatchInboundDirectDmWithRuntime`
with namespaced peer ID and `extraContext` override:
- Peer ID: `board:${boardName}` (namespaced to avoid session key collision with DM peers)
- `extraContext: { ChatType: "group", GroupSubject: boardName, SenderName: message.senderId }`
- This overrides the hardcoded `ChatType: "direct"` because `extraContext` is spread last in the
  `finalizeInboundContext` call inside `dispatchInboundDirectDmWithRuntime`.

```typescript
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  cfg: CoreConfig;
  pairing: ReturnType<typeof createChannelPairingController>;
  sendReply: (to: string, text: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, cfg } = params;
  const runtime = getPulseBoardRuntime();
  const rawBody = message.text.trim();
  if (!rawBody) return;

  params.statusSink?.({ lastInboundAt: message.timestamp });

  if (message.isGroup && message.boardName) {
    // Board (group) path
    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: "pulseboard",
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: `board:${message.boardName}` },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:board:${message.boardName}`,
      conversationLabel: message.boardName,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      // Override ChatType and inject group metadata via extraContext
      extraContext: {
        ChatType: "group",
        GroupSubject: message.boardName,
        SenderName: message.senderId,
        From: `pulseboard:board:${message.boardName}`,
      },
      deliver: async (payload) => {
        const text = extractText(payload);
        if (text.trim()) {
          await params.sendReply(`board:${message.boardName}`, text);
        }
      },
      onRecordError: (err) => runtime.error?.(`pulseboard: record error: ${String(err)}`),
      onDispatchError: (err, info) =>
        runtime.error?.(`pulseboard: ${info.kind} reply failed: ${String(err)}`),
    });
  } else {
    // DM path — resolve DM access first
    const resolvedAccess = await resolveInboundDirectDmAccessWithRuntime({
      cfg,
      channel: "pulseboard",
      accountId: account.accountId,
      dmPolicy: account.config.dmPolicy ?? "pairing",
      allowFrom: account.config.allowFrom,
      senderId: message.senderId,
      rawBody,
      isSenderAllowed: (senderId, allowFrom) =>
        allowFrom.includes("*") || allowFrom.map(String).includes(senderId),
      runtime: {
        shouldComputeCommandAuthorized:
          runtime.channel.commands.shouldComputeCommandAuthorized,
        resolveCommandAuthorizedFromAuthorizers:
          runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
      },
      modeWhenAccessGroupsOff: "configured",
    });

    if (resolvedAccess.access.decision === "pairing") {
      await params.pairing.issueChallenge({
        senderId: message.senderId,
        senderIdLine: `Your PulseBoard username: ${message.senderId}`,
        sendPairingReply: async (text) => {
          await params.sendReply(message.senderId, text);
        },
        onReplyError: (err) =>
          runtime.error?.(
            `pulseboard: pairing reply failed for ${message.senderId}: ${String(err)}`,
          ),
      });
      return;
    }
    if (resolvedAccess.access.decision !== "allow") {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: "pulseboard",
        reason: resolvedAccess.access.reason,
        target: message.senderId,
      });
      return;
    }

    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: "pulseboard",
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: message.senderId },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:${account.username ?? account.accountId}`,
      conversationLabel: message.senderId,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      commandAuthorized: resolvedAccess.commandAuthorized,
      deliver: async (payload) => {
        const text = extractText(payload);
        if (text.trim()) {
          await params.sendReply(message.senderId, text);
        }
      },
      onRecordError: (err) => runtime.error?.(`pulseboard: record error: ${String(err)}`),
      onDispatchError: (err, info) =>
        runtime.error?.(`pulseboard: ${info.kind} reply failed: ${String(err)}`),
    });
  }
}
```

