### Step 11: `extensions/pulseboard/src/monitor.ts`

Gateway connection loop. Uses `runStoppablePassiveMonitor` (same as IRC).

```typescript
export async function monitorPulseBoardProvider(opts: {
  accountId: string;
  cfg: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<{ stop: () => void }> {
  const runtime = getPulseBoardRuntime();
  const account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });
  const pairing = createChannelPairingController({ core: runtime, channel: "pulseboard", accountId: opts.accountId });

  const client = await connectPulseBoardClient({
    serverUrl: account.serverUrl,
    token: account.token,
    username: account.username,
    onMessage: async (msg) => {
      await handlePulseBoardInbound({
        message: msg, account, cfg: opts.cfg, pairing,
        sendReply: async (to, text) => {
          await sendMessagePulseBoard({ to, text, accountId: account.accountId });
          opts.statusSink?.({ lastOutboundAt: Date.now() });
        },
        statusSink: opts.statusSink,
      });
    },
    onConnect: () => runtime.log?.(`[${account.accountId}] PulseBoard connected`),
    onDisconnect: (reason) => runtime.log?.(`[${account.accountId}] PulseBoard disconnected: ${reason}`),
    onError: (err) => runtime.error?.(`[${account.accountId}] PulseBoard error: ${err.message}`),
  });

  setPulseBoardClient(account.accountId, client);
  return { stop: () => { client.close(); clearPulseBoardClient(account.accountId); } };
}
```

