### Step 10: `extensions/pulseboard/src/inbound.ts`

Inbound message handler. Handles both DM and board messages.

**DM path** — follows Nostr's `onMessage` handler:
- Resolve DM access with `resolveInboundDirectDmAccessWithRuntime` (requires `isSenderAllowed`)
- Dispatch with `dispatchInboundDirectDmWithRuntime` where `peer: { kind: "direct", id: senderId }`

**Board path** — follows IRC's group pattern but uses the same `dispatchInboundDirectDmWithRuntime`
with namespaced peer ID and `extraContext` override:
- Peer ID: `board:${boardName}` (namespaced to avoid session key collision with DM peers)
- `extraContext: { ChatType: "group", GroupSubject: boardName, SenderName: message.senderId }`
- This overrides the hardcoded `ChatType: "direct"` because `extraContext` is spread last in the
  `finalizeInboundContext` call inside `dispatchInboundDirectDmWithRuntime`.

```typescript
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  cfg: CoreConfig;
  pairing: ReturnType<typeof createChannelPairingController>;
  sendReply: (to: string, text: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, cfg } = params;
  const runtime = getPulseBoardRuntime();
  const rawBody = message.text.trim();
  if (!rawBody) return;

  params.statusSink?.({ lastInboundAt: message.timestamp });

  if (message.isGroup && message.boardName) {
    // Board (group) path
    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: "pulseboard",
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: `board:${message.boardName}` },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:board:${message.boardName}`,
      conversationLabel: message.boardName,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      // Override ChatType and inject group metadata via extraContext
      extraContext: {
        ChatType: "group",
        GroupSubject: message.boardName,
        SenderName: message.senderId,
        From: `pulseboard:board:${message.boardName}`,
      },
      deliver: async (payload) => {
        const text = extractText(payload);
        if (text.trim()) {
          await params.sendReply(`board:${message.boardName}`, text);
        }
      },
      onRecordError: (err) => runtime.error?.(`pulseboard: record error: ${String(err)}`),
      onDispatchError: (err, info) =>
        runtime.error?.(`pulseboard: ${info.kind} reply failed: ${String(err)}`),
    });
  } else {
    // DM path — resolve DM access first
    const resolvedAccess = await resolveInboundDirectDmAccessWithRuntime({
      cfg,
      channel: "pulseboard",
      accountId: account.accountId,
      dmPolicy: account.config.dmPolicy ?? "pairing",
      allowFrom: account.config.allowFrom,
      senderId: message.senderId,
      rawBody,
      isSenderAllowed: (senderId, allowFrom) =>
        allowFrom.includes("*") || allowFrom.map(String).includes(senderId),
      runtime: {
        shouldComputeCommandAuthorized:
          runtime.channel.commands.shouldComputeCommandAuthorized,
        resolveCommandAuthorizedFromAuthorizers:
          runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
      },
      modeWhenAccessGroupsOff: "configured",
    });

    if (resolvedAccess.access.decision === "pairing") {
      await params.pairing.issueChallenge({
        senderId: message.senderId,
        senderIdLine: `Your PulseBoard username: ${message.senderId}`,
        sendPairingReply: async (text) => {
          await params.sendReply(message.senderId, text);
        },
        onReplyError: (err) =>
          runtime.error?.(
            `pulseboard: pairing reply failed for ${message.senderId}: ${String(err)}`,
          ),
      });
      return;
    }
    if (resolvedAccess.access.decision !== "allow") {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: "pulseboard",
        reason: resolvedAccess.access.reason,
        target: message.senderId,
      });
      return;
    }

    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: "pulseboard",
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: message.senderId },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:${account.username ?? account.accountId}`,
      conversationLabel: message.senderId,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      commandAuthorized: resolvedAccess.commandAuthorized,
      deliver: async (payload) => {
        const text = extractText(payload);
        if (text.trim()) {
          await params.sendReply(message.senderId, text);
        }
      },
      onRecordError: (err) => runtime.error?.(`pulseboard: record error: ${String(err)}`),
      onDispatchError: (err, info) =>
        runtime.error?.(`pulseboard: ${info.kind} reply failed: ${String(err)}`),
    });
  }
}
```

---

### Step 11: `extensions/pulseboard/src/monitor.ts`

Gateway connection loop. Uses `runStoppablePassiveMonitor` (same as IRC).

```typescript
export async function monitorPulseBoardProvider(opts: {
  accountId: string;
  cfg: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<{ stop: () => void }> {
  const runtime = getPulseBoardRuntime();
  const account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });
  const pairing = createChannelPairingController({ core: runtime, channel: "pulseboard", accountId: opts.accountId });

  const client = await connectPulseBoardClient({
    serverUrl: account.serverUrl,
    token: account.token,
    username: account.username,
    onMessage: async (msg) => {
      await handlePulseBoardInbound({
        message: msg, account, cfg: opts.cfg, pairing,
        sendReply: async (to, text) => {
          await sendMessagePulseBoard({ to, text, accountId: account.accountId });
          opts.statusSink?.({ lastOutboundAt: Date.now() });
        },
        statusSink: opts.statusSink,
      });
    },
    onConnect: () => runtime.log?.(`[${account.accountId}] PulseBoard connected`),
    onDisconnect: (reason) => runtime.log?.(`[${account.accountId}] PulseBoard disconnected: ${reason}`),
    onError: (err) => runtime.error?.(`[${account.accountId}] PulseBoard error: ${err.message}`),
  });

  setPulseBoardClient(account.accountId, client);
  return { stop: () => { client.close(); clearPulseBoardClient(account.accountId); } };
}
```

---

### Step 12: `extensions/pulseboard/src/setup-surface.ts`

Setup adapter and wizard. Follows Nostr's `setup-surface.ts` pattern.

`nostrSetupAdapter` → `pulseBoardSetupAdapter`:
- `resolveAccountId: () => DEFAULT_ACCOUNT_ID`
- `validateInput`: require `token` (or `useEnv`); validate `serverUrl` as ws:// or wss://
- `applyAccountConfig`: call `patchTopLevelChannelConfigSection({ channel: "pulseboard", ... })`

`pulseBoardSetupWizard`:
- `credentials`: `token` input (env var: `PULSEBOARD_TOKEN`)
- `textInputs`: `serverUrl` (ws:// / wss://) and `username` fields
- `dmPolicy`: `createTopLevelChannelDmPolicy` for `channels.pulseboard.dmPolicy`
- `introNote`, `envShortcut`, `status` (via `createStandardChannelSetupStatus`)

---

### Step 13: `extensions/pulseboard/src/channel.ts`

Main plugin definition. Uses `createChatChannelPlugin`.

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin boards and direct messages via PulseBoard",
      order: 90,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,          // createTopLevelChannelConfigAdapter
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: { serverUrl: account.serverUrl, username: account.username },
        }),
    },
    messaging: {
      normalizeTarget: (target) => {
        // Accept "board:<name>" for boards, plain username for DMs
        const trimmed = target.trim().replace(/^pulseboard:/i, "");
        return trimmed || undefined;
      },
      targetResolver: {
        looksLikeId: (input) => {
          const t = input.trim();
          return t.startsWith("board:") || /^[a-zA-Z0-9_.-]+$/.test(t);
        },
        hint: "<username|board:<name>>",
      },
    },
    status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
      defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
      collectStatusIssues: (accounts) =>
        collectStatusIssuesFromLastError("pulseboard", accounts),
      buildChannelSummary: ({ snapshot }) =>
        buildPassiveChannelStatusSummary(snapshot, {
          serverUrl: snapshot.serverUrl ?? null,
          username: snapshot.username ?? null,
        }),
      resolveAccountSnapshot: ({ account, runtime }) => ({
        accountId: account.accountId,
        name: account.name,
        enabled: account.enabled,
        configured: account.configured,
        extra: {
          serverUrl: account.serverUrl,
          username: account.username,
          ...buildTrafficStatusSummary(runtime),
        },
      }),
    }),
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" (need token in channels.pulseboard).`,
          );
        }
        ctx.log?.info(`[${account.accountId}] starting PulseBoard provider (${account.serverUrl})`);
        await runStoppablePassiveMonitor({
          abortSignal: ctx.abortSignal,
          start: async () =>
            await monitorPulseBoardProvider({
              accountId: account.accountId,
              cfg: ctx.cfg as CoreConfig,
              abortSignal: ctx.abortSignal,
            }),
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: "Your pairing request has been approved!",
      normalizeAllowEntry: (entry) => entry.trim().toLowerCase(),
      notify: async ({ id, message }) => {
        await sendMessagePulseBoard({ to: id, text: message });
      },
    },
  },
  security: {
    resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
      channelKey: "pulseboard",
      resolvePolicy: (account) => account.config.dmPolicy,
      resolveAllowFrom: (account) => account.config.allowFrom,
      policyPathSuffix: "dmPolicy",
      defaultPolicy: "pairing",
      // approveHint omitted — createScopedDmSecurityResolver generates default hint from channelKey
      normalizeEntry: (raw) => raw.trim().toLowerCase(),
    }),
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseBoardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg, channel: "pulseboard", accountId: aid,
      });
      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
      const result = await sendMessagePulseBoard({ to, text: message, accountId: aid });
      return attachChannelToResult("pulseboard", result);
    },
  },
});
```

