### Step 8: `extensions/pulseboard/src/client.ts`

Fictional PulseBoard WebSocket client. This is a stub that provides a realistic interface without
real protocol implementation. Key exports:

```typescript
export type PulseBoardClientOptions = {
  serverUrl: string;
  token: string;
  username: string;
  onMessage: (msg: PulseBoardInboundMessage) => void | Promise<void>;
  onConnect?: () => void;
  onDisconnect?: (reason: string) => void;
  onError?: (err: Error) => void;
};

export type PulseBoardClientHandle = {
  /** Send a direct message to another user. */
  sendDm(toUserId: string, text: string): Promise<void>;
  /** Post a message to a named board. */
  postToBoard(boardName: string, text: string): Promise<void>;
  /** Gracefully disconnect. */
  close(): void;
  /** Whether the client is connected and ready. */
  isConnected(): boolean;
};

export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClientHandle> {
  // Stub implementation: logs operations, simulates connected state.
  // Real implementation would open a WebSocket to opts.serverUrl,
  // authenticate with opts.token, and dispatch incoming events to onMessage.
  let connected = true;
  return {
    sendDm: async (toUserId, text) => { /* stub */ },
    postToBoard: async (boardName, text) => { /* stub */ },
    close: () => { connected = false; opts.onDisconnect?.("closed"); },
    isConnected: () => connected,
  };
}
```

---

### Step 9: `extensions/pulseboard/src/send.ts`

Outbound message sending. Mirrors Nostr's inline send but extracts it to a dedicated file
like IRC's `send.ts`. Accesses the active client handle stored during gateway startup.

```typescript
// Module-level map of active client handles per accountId
const activeClients = new Map<string, PulseBoardClientHandle>();

export function setPulseBoardClient(accountId: string, client: PulseBoardClientHandle): void { ... }
export function clearPulseBoardClient(accountId: string): void { ... }

export async function sendMessagePulseBoard(params: {
  to: string;         // "board:<name>" or "<userId>"
  text: string;
  accountId?: string | null;
}): Promise<{ to: string; messageId: string }> {
  const aid = normalizeAccountId(params.accountId ?? DEFAULT_ACCOUNT_ID);
  const client = activeClients.get(aid);
  if (!client?.isConnected()) {
    throw new Error(`PulseBoard client not running for account ${aid}`);
  }
  if (params.to.startsWith("board:")) {
    const boardName = params.to.slice("board:".length);
    await client.postToBoard(boardName, params.text);
  } else {
    await client.sendDm(params.to, params.text);
  }
  return { to: params.to, messageId: `pb-${Date.now()}` };
}
```

