import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { OpenClawConfig } from "../runtime-api.js";

// Per-board group configuration overrides.
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  allowFrom?: Array<string | number>;
  systemPrompt?: string;
};

// Top-level channels.pulseboard configuration.
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** API token for authenticating with the PulseBoard server. */
  token?: SecretInput;
  /** WebSocket URL of the PulseBoard server (e.g. wss://pb.example.com). */
  serverUrl?: string;
  /** Bot username on PulseBoard. */
  username?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  groupPolicy?: "open" | "allowlist" | "blocked";
  groupAllowFrom?: Array<string | number>;
  /** Per-board configuration overrides keyed by board name. */
  boards?: Record<string, PulseBoardBoardConfig>;
};

// Resolved runtime account after merging config and env vars.
export type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  /** True when token is present and non-empty. */
  configured: boolean;
  token: string;
  serverUrl: string;
  username: string;
  config: PulseBoardAccountConfig;
};

// Inbound message from the PulseBoard client.
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Username of the sender. */
  senderId: string;
  /** Set for board (group) messages; absent for direct messages. */
  boardName?: string;
  text: string;
  timestamp: number;
  /** True for board posts, false for direct messages. */
  isGroup: boolean;
};

// Augmented config type with typed pulseboard channel section.
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardAccountConfig;
  };
};

const DEFAULT_SERVER_URL = "wss://pb.example.com";
const DEFAULT_USERNAME = "openclaw";

function resolveConfiguredDefaultPulseBoardAccountId(cfg: OpenClawConfig): string | undefined {
  const pbCfg = (cfg as CoreConfig).channels?.pulseboard;
  return normalizeOptionalAccountId(pbCfg?.name);
}

/** List all configured PulseBoard account IDs. */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg as CoreConfig).channels?.pulseboard;
  const token = normalizeSecretInputString(pbCfg?.token);
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: token
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/** Get the default account ID. */
export function resolveDefaultPulseBoardAccountId(cfg: OpenClawConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/** Resolve a PulseBoard account from config. */
export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg as CoreConfig).channels?.pulseboard;
  const baseEnabled = pbCfg?.enabled !== false;
  const token = normalizeSecretInputString(pbCfg?.token) ?? "";
  const configured = Boolean(token);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    token,
    serverUrl: pbCfg?.serverUrl?.trim() || DEFAULT_SERVER_URL,
    username: pbCfg?.username?.trim() || DEFAULT_USERNAME,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      token: pbCfg?.token,
      serverUrl: pbCfg?.serverUrl,
      username: pbCfg?.username,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
      groupPolicy: pbCfg?.groupPolicy,
      groupAllowFrom: pbCfg?.groupAllowFrom,
      boards: pbCfg?.boards,
    },
  };
}

