import type { PulseBoardInboundMessage } from "./types.js";

export type PulseBoardClientOptions = {
  serverUrl: string;
  token: string;
  username: string;
  onMessage: (msg: PulseBoardInboundMessage) => void | Promise<void>;
  onConnect?: () => void;
  onDisconnect?: (reason: string) => void;
  onError?: (err: Error) => void;
};

export type PulseBoardClientHandle = {
  /**
   * Send a direct message to another PulseBoard user.
   * @param toUserId - Recipient's username.
   * @param text - Message body.
   */
  sendDm(toUserId: string, text: string): Promise<void>;
  /**
   * Post a message to a named board.
   * @param boardName - Target board name.
   * @param text - Message body.
   */
  postToBoard(boardName: string, text: string): Promise<void>;
  /** Gracefully disconnect from the PulseBoard server. */
  close(): void;
  /** Returns true when the client is connected and ready to send. */
  isConnected(): boolean;
};

/**
 * Connect to a PulseBoard server and return a client handle.
 *
 * This is a stub implementation for the fictional PulseBoard protocol.
 * A real implementation would open a persistent WebSocket connection to
 * opts.serverUrl, authenticate using opts.token, subscribe to inbound events,
 * and stream them to opts.onMessage.
 *
 * Env vars respected: PULSEBOARD_TOKEN, PULSEBOARD_SERVER_URL.
 */
export async function connectPulseBoardClient(
  opts: PulseBoardClientOptions,
): Promise<PulseBoardClientHandle> {
  let connected = true;

  // Notify caller that the connection is established.
  opts.onConnect?.();

  return {
    sendDm: async (toUserId: string, _text: string) => {
      if (!connected) {
        throw new Error(`PulseBoard client is not connected (account: ${opts.username})`);
      }
      // Stub: a real implementation would POST or send via WebSocket frame.
      void toUserId;
    },

    postToBoard: async (boardName: string, _text: string) => {
      if (!connected) {
        throw new Error(`PulseBoard client is not connected (account: ${opts.username})`);
      }
      // Stub: a real implementation would POST or send via WebSocket frame.
      void boardName;
    },

    close: () => {
      connected = false;
      opts.onDisconnect?.("closed");
    },

    isConnected: () => connected,
  };
}

