import {
  createChannelPairingController,
  dispatchInboundDirectDmWithRuntime,
  logInboundDrop,
  resolveInboundDirectDmAccessWithRuntime,
} from "../runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage, ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

/** Extract plain text from an outbound reply payload. */
function extractReplyText(payload: unknown): string {
  if (payload && typeof payload === "object" && "text" in payload) {
    return String((payload as { text?: string }).text ?? "");
  }
  return "";
}

/** Check whether a sender username is in the allowlist. */
function isPulseBoardSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalized = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    const entryStr = String(entry).trim().toLowerCase();
    if (entryStr === "*" || entryStr === normalized) {
      return true;
    }
  }
  return false;
}

/**
 * Handle an inbound PulseBoard message (direct or board).
 *
 * Board (group) path:
 *   Routes to a session keyed by "board:<boardName>". The peer ID is namespaced
 *   to prevent session key collisions with same-named DM users. ChatType is
 *   overridden to "group" via extraContext, which is spread after the hardcoded
 *   "direct" value inside dispatchInboundDirectDmWithRuntime.
 *
 * DM path:
 *   Resolves DM access policy (pairing / allowlist / open / disabled) before
 *   dispatching, issuing a pairing challenge when needed.
 */
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  cfg: CoreConfig;
  pairing: ReturnType<typeof createChannelPairingController>;
  sendReply: (to: string, text: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, cfg } = params;
  const runtime = getPulseBoardRuntime();
  const rawBody = message.text.trim();

  if (!rawBody) {
    return;
  }

  params.statusSink?.({ lastInboundAt: message.timestamp });

  if (message.isGroup && message.boardName) {
    // Board (group) path.
    // Peer ID is "board:<boardName>" to keep board sessions distinct from DM sessions
    // with the same name. extraContext overrides ChatType since it is spread last in
    // finalizeInboundContext inside dispatchInboundDirectDmWithRuntime.
    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: CHANNEL_ID,
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: `board:${message.boardName}` },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:board:${message.boardName}`,
      conversationLabel: message.boardName,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      // Override ChatType to "group" and inject group metadata.
      // extraContext is spread last in finalizeInboundContext so it wins.
      extraContext: {
        ChatType: "group",
        GroupSubject: message.boardName,
        SenderName: message.senderId,
        From: `pulseboard:board:${message.boardName}`,
      },
      deliver: async (payload) => {
        const text = extractReplyText(payload);
        if (text.trim()) {
          await params.sendReply(`board:${message.boardName}`, text);
        }
      },
      onRecordError: (err) => {
        runtime.error?.(
          `pulseboard: record error for board "${message.boardName}": ${String(err)}`,
        );
      },
      onDispatchError: (err, info) => {
        runtime.error?.(
          `pulseboard: board "${message.boardName}" ${info.kind} reply failed: ${String(err)}`,
        );
      },
    });
  } else {
    // DM path: resolve access policy before dispatching.
    const resolvedAccess = await resolveInboundDirectDmAccessWithRuntime({
      cfg,
      channel: CHANNEL_ID,
      accountId: account.accountId,
      dmPolicy: account.config.dmPolicy ?? "pairing",
      allowFrom: account.config.allowFrom,
      senderId: message.senderId,
      rawBody,
      isSenderAllowed: isPulseBoardSenderAllowed,
      runtime: {
        shouldComputeCommandAuthorized:
          runtime.channel.commands.shouldComputeCommandAuthorized,
        resolveCommandAuthorizedFromAuthorizers:
          runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
      },
      modeWhenAccessGroupsOff: "configured",
    });

    if (resolvedAccess.access.decision === "pairing") {
      await params.pairing.issueChallenge({
        senderId: message.senderId,
        senderIdLine: `Your PulseBoard username: ${message.senderId}`,
        sendPairingReply: async (text) => {
          await params.sendReply(message.senderId, text);
        },
        onReplyError: (err) => {
          runtime.error?.(
            `pulseboard: pairing reply failed for "${message.senderId}": ${String(err)}`,
          );
        },
      });
      return;
    }

    if (resolvedAccess.access.decision !== "allow") {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: CHANNEL_ID,
        reason: resolvedAccess.access.reason,
        target: message.senderId,
      });
      return;
    }

    await dispatchInboundDirectDmWithRuntime({
      cfg,
      runtime,
      channel: CHANNEL_ID,
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: message.senderId },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:${account.username}`,
      conversationLabel: message.senderId,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      commandAuthorized: resolvedAccess.commandAuthorized,
      deliver: async (payload) => {
        const text = extractReplyText(payload);
        if (text.trim()) {
          await params.sendReply(message.senderId, text);
        }
      },
      onRecordError: (err) => {
        runtime.error?.(
          `pulseboard: record error for "${message.senderId}": ${String(err)}`,
        );
      },
      onDispatchError: (err, info) => {
        runtime.error?.(
          `pulseboard: DM to "${message.senderId}" ${info.kind} reply failed: ${String(err)}`,
        );
      },
    });
  }
}

