import { createChannelPairingController } from "../runtime-api.js";
import { connectPulseBoardClient } from "./client.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { clearPulseBoardClient, sendMessagePulseBoard, setPulseBoardClient } from "./send.js";
import { resolvePulseBoardAccount, type CoreConfig } from "./types.js";

/**
 * Start and manage a PulseBoard gateway connection for one account.
 *
 * Called by channel.ts gateway.startAccount via runStoppablePassiveMonitor.
 * Connects the fictional PulseBoard WebSocket client, registers the active
 * client handle for outbound sends, and dispatches inbound messages.
 *
 * Returns { stop } to allow runStoppablePassiveMonitor to clean up on abort.
 */
export async function monitorPulseBoardProvider(opts: {
  accountId: string;
  cfg: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<{ stop: () => void }> {
  const runtime = getPulseBoardRuntime();
  const account = resolvePulseBoardAccount({ cfg: opts.cfg, accountId: opts.accountId });

  const pairing = createChannelPairingController({
    core: runtime,
    channel: "pulseboard",
    accountId: account.accountId,
  });

  const client = await connectPulseBoardClient({
    serverUrl: account.serverUrl,
    token: account.token,
    username: account.username,
    onMessage: async (msg) => {
      await handlePulseBoardInbound({
        message: msg,
        account,
        cfg: opts.cfg,
        pairing,
        sendReply: async (to, text) => {
          await sendMessagePulseBoard({ to, text, accountId: account.accountId });
          opts.statusSink?.({ lastOutboundAt: Date.now() });
        },
        statusSink: (patch) => opts.statusSink?.(patch),
      });
    },
    onConnect: () => {
      runtime.log?.(`[${account.accountId}] PulseBoard connected to ${account.serverUrl}`);
    },
    onDisconnect: (reason) => {
      runtime.log?.(`[${account.accountId}] PulseBoard disconnected: ${reason}`);
    },
    onError: (err) => {
      runtime.error?.(`[${account.accountId}] PulseBoard error: ${err.message}`);
    },
  });

  setPulseBoardClient(account.accountId, client);
  runtime.log?.(`[${account.accountId}] PulseBoard provider started`);

  return {
    stop: () => {
      client.close();
      clearPulseBoardClient(account.accountId);
      runtime.log?.(`[${account.accountId}] PulseBoard provider stopped`);
    },
  };
}

